INSERT INTO cr_object_information (object_id,info_type,info_value,info_description,additional_information1,additional_information2,additional_information3,additional_information4,additional_information5,creation_date,created_by,last_update_date,last_update_by,attribute1,attribute2,attribute3,attribute4,attribute5,attribute6,attribute7,attribute8,attribute9,attribute10,attribute11,attribute12,attribute13,attribute14,attribute15) VALUES
	 (4,'InterfaceDetails','23','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'DocumentAccount','prc/blanketPurchaseAgreement/import','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'RECON_CLOUD_SUCCESS','SELECT :src_cols from      PO_HEADERS_ALL base,     PO_HEADERS_INTERFACE INT,     :cld_stg_table cld_stg,      :src_stg_table src_stg where     1=1     and INT.po_header_id = BASE.po_header_id     and int.DOCUMENT_NUM = base.segment1     AND INT.DOCUMENT_NUM= cld_stg.DOCUMENT_NUM     and INT.PROCESS_CODE = ''ACCEPTED''      and INT.load_request_id ='':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name''     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','','base.po_header_id base_po_header_id,     base.billto_bu_id base_billto_bu_id,     base.soldto_le_id base_soldto_le_id,     base.document_status base_document_status,     base.prc_bu_id base_prc_bu_id,     base.req_bu_id base_req_bu_id,     base.segment1 base_segment1,     base.vendor_id base_vendor_id,     base.vendor_site_id base_vendor_site_id,     base.vendor_contact_id base_vendor_contact_id,     base.ship_to_location_id base_ship_to_location_id,     base.bill_to_location_id base_bill_to_location_id,     base.terms_id base_terms_id',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'RECON_CLOUD_FAIL','SELECT     :src_cols     || '',''     || ''"''     ||     (         SELECT               listagg (error_message,'','') WITHIN GROUP (ORDER BY interface_header_id)  error_msg         FROM             po_interface_errors         where                 interface_header_id = int.interface_header_id         GROUP BY              interface_header_id || ''"''     ) Error_Message FROM     PO_HEADERS_INTERFACE INT,     :cld_stg_table cld_stg,      :src_stg_table src_stg WHERE     1=1     and INT.load_request_id = '':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name''  AND INT.DOCUMENT_NUM= cld_stg.DOCUMENT_NUM     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'JobName','/oracle/apps/ess/prc/po/pdoi/,ImportBPAJob','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'RECON_CLOUD_FAIL_COUNT','SELECT      count(1)  FROM 	     PO_HEADERS_INTERFACE  WHERE 	     1=1     AND PROCESS_CODE <>''ACCEPTED''      AND DOCUMENT_TYPE_CODE = ''BLANKET''     AND load_request_id = '':load_request_id''','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'SQL_EXTRACTION_QUERY','SELECT
    poh.po_header_id                                              interface_header_key,
    ''ORIGINAL''                                                    action,
    NULL                                                          batch_id,
    poh.interface_source_code                                     interface_source_code,
    poh.authorization_status                                      approval_action,
    poh.segment1                                                  document_num,
    ''BLANKET''                                                     document_type_code,
    NULL                                                          style_display_name,
    (
        SELECT
            bill_hou.name
        FROM
            hr_operating_units bill_hou
        WHERE
            bill_hou.organization_id = poh.org_id
    )                                                             Procurement_BU,
    (
        SELECT
            papf.last_name
            || '', ''
            || papf.first_name
        FROM
            per_all_people_f papf
        WHERE
                papf.person_id = poh.agent_id
            AND nvl(trunc(papf.effective_end_date),
                    trunc(sysdate)) >= trunc(sysdate)
    )                                                             agent_name,
    poh.currency_code,
    poh.comments,
    pv.vendor_name                                                vendor_name,
    pv.segment1                                                   vendor_number,
    pvs.vendor_site_code                                          vendor_site_code,
    (
       pvc.first_name
            || '' ''
            || pvc.last_name
    )                                                             vendor_contact,
    poh.vendor_order_num                                          vendor_doc_num,
    poh.fob_lookup_code                                           fob,
    NULL                                                          freight_carrier,
    poh.freight_terms_lookup_code                                 freight_terms,
    poh.pay_on_code                                               pay_on_code,
    att.name                                                      payment_terms,
    ''BUYER''                                                       originator_role,
    NULL                                                          change_order_desc,
    poh.acceptance_required_flag                                  acceptance_required_flag,
    ( trunc(poh.acceptance_due_date) - trunc(poh.approved_date) ) acceptance_within_days,
    --poh.supplier_notif_method                                     supplier_notif_method,
    --poh.fax                                                       fax,
   (SELECT
            ppf.email_address
        FROM
            apps.per_all_people_f ppf
        WHERE
            ppf.person_id = poh.agent_id
            AND SYSDATE BETWEEN ppf.effective_start_date AND ppf.effective_end_date) email_address,
    poh.confirming_order_flag,
    poh.blanket_total_amount                                      amount_agreed,
    poh.amount_limit,
    poh.min_release_amount,
    poh.start_date,
    poh.end_date,
    poh.note_to_vendor,
    poh.note_to_receiver,
    NULL                                                          generate_orders_automatic,
    NULL                                                          submit_approval_automatic,
    NULL                                                          group_requisitions,
    NULL                                                          group_requisition_lines,
    NULL                                                          use_ship_to,
    NULL                                                          use_need_by_date,
    NULL                                                          cat_admin_auth_enabled_flag,
    NULL                                                          retro_price_apply_updates_flag,
    NULL                                                          retro_price_comm_updates_flag,
    poh.attribute_category                                        attribute_category,
    poh.attribute1                                                attribute1,
    poh.attribute2                                                attribute2,
    poh.attribute3                                                attribute3,
    poh.attribute4                                                attribute4,
    poh.attribute5                                                attribute5,
    poh.attribute6                                                attribute6,
    poh.attribute7                                                attribute7,
    poh.attribute8                                                attribute8,
    poh.attribute9                                                attribute9,
    poh.attribute10                                               attribute10,
    poh.attribute11                                               attribute11,
    poh.attribute12                                               attribute12,
    poh.attribute13                                               attribute13,
    poh.attribute14                                               attribute14,
    poh.attribute15                                               attribute15,
    NULL                                                          attribute16,
    NULL                                                          attribute17,
    NULL                                                          attribute18,
    NULL                                                          attribute19,
    NULL                                                          attribute20,
    NULL                                                          attribute_date1,
    NULL                                                          attribute_date2,
    NULL                                                          attribute_date3,
    NULL                                                          attribute_date4,
    NULL                                                          attribute_date5,
    NULL                                                          attribute_date6,
    NULL                                                          attribute_date7,
    NULL                                                          attribute_date8,
    NULL                                                          attribute_date9,
    NULL                                                          attribute_date10,
    NULL                                                          attribute_number1,
    NULL                                                          attribute_number2,
    NULL                                                          attribute_number3,
    NULL                                                          attribute_number4,
    NULL                                                          attribute_number5,
    NULL                                                          attribute_number6,
    NULL                                                          attribute_number7,
    NULL                                                          attribute_number8,
    NULL                                                          attribute_number9,
    NULL                                                          attribute_number10,
    NULL                                                          attribute_timestamp1,
    NULL                                                          attribute_timestamp2,
    NULL                                                          attribute_timestamp3,
    NULL                                                          attribute_timestamp4,
    NULL                                                          attribute_timestamp5,
    NULL                                                          attribute_timestamp6,
    NULL                                                          attribute_timestamp7,
    NULL                                                          attribute_timestamp8,
    NULL                                                          attribute_timestamp9,
    NULL                                                          attribute_timestamp10,
    (
        SELECT
            papf.email_address
        FROM
            per_all_people_f papf
        WHERE
                papf.person_id = poh.agent_id
            AND current_employee_flag = ''Y''
            AND nvl(trunc(papf.effective_end_date),
                    trunc(sysdate)) >= trunc(sysdate)
    )                                                             agent_email_address,
    NULL                                                          mode_of_transport,
    NULL                                                          service_level,
    NULL                                                          aging_period_days,
    NULL                                                          aging_onset_point,
    NULL                                                          consumption_advice_frequency,
    NULL                                                          consumption_advice_summary,
    NULL                                                          default_consignment_line_flag,
    NULL                                                          pay_on_use_flag,
    NULL                                                          billing_cycle_closing_date,
    NULL                                                          configured_item_flag,
    NULL                                                          use_sales_order_number_flag,
    NULL                                                          buyer_managed_transport_flag,
    NULL                                                          allow_multiple_sites_flag,
    NULL                                                          outside_process_enabled_flag,
    NULL                                                          master_contract_number,
    NULL                                                          master_contract_type,
    NULL                                                          use_order_date_in_pricing_flag
FROM
    apps.po_headers_all      poh,
    apps.po_vendors          pv,
    apps.po_vendor_sites_all pvs,
    apps.po_vendor_contacts  pvc,
    apps.ap_terms_tl         att,
	hr_operating_units hou
WHERE
        1 = 1
    AND poh.vendor_id = pv.vendor_id(+)
    AND poh.vendor_site_id = pvs.vendor_site_id(+)
    AND poh.vendor_contact_id = pvc.vendor_contact_id (+)
    AND pv.vendor_id = pvs.vendor_id
    --AND pvs.vendor_site_id(+) = pvc.vendor_site_id 
    AND poh.type_lookup_code = ''BLANKET''
    AND poh.authorization_status IN ( ''APPROVED'' )
	AND poh.enabled_flag = ''Y''
    AND nvl(poh.closed_code, ''OPEN'') = ''OPEN''
    AND poh.terms_id = att.term_id (+)
    AND att.language (+) = userenv(''lang'')
	AND hou.ORGANIZATION_ID = poh.org_id
     and  hou.name in (''Biomet 3i Canada'',
													''Zimmer Dental SAS'',
													''JP OU'',
													''3i US'',
													''Biomet 3i Dental Iberica SLU'')
    AND nvl(
            poh.end_date,
            SYSDATE + 1
        ) > SYSDATE
    AND EXISTS (
            SELECT
                ''x''
            FROM
                apps.po_lines_all pl
            WHERE
                pl.po_header_id = poh.po_header_id
                AND nvl(
                    pl.closed_code,
                    ''OPEN''
                ) = ''OPEN''
                AND nvl(
                    pl.cancel_flag,
                    ''N''
                ) = ''N''
                AND nvl(
                    pl.expiration_date,
                    SYSDATE + 1
                ) > SYSDATE
        ) 
        order by poh.segment1','',NULL,NULL,NULL,NULL,NULL,'2025-01-02','riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'DocumentSecurityGroup','FAFusionImportExport','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (4,'Sequence','1','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (5,'InterfaceDetails','23','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
