	 (5,'RECON_CLOUD_FAIL','SELECT     :src_cols     ||      '',''     || ''"''     ||     (         SELECT               listagg (error_message,'','') WITHIN GROUP (ORDER BY interface_header_id)  error_msg         FROM             po_interface_errors         where                 interface_header_id = int.interface_header_id         GROUP BY              interface_header_id || ''"''     ) Error_Message FROM     PO_LINES_INTERFACE INT,       :cld_stg_table cld_stg,      :src_stg_table src_stg WHERE     1=1     and INT.load_request_id = '':load_request_id''     and cld_stg.cr_batch_name ='':cr_batch_name''     AND INT.PROCESS_CODE <>''ACCEPTED''      AND INT.CATEGORY= cld_stg.CATEGORY     AND INT.ITEM= cld_stg.ITEM     AND INT.INTERFACE_LINE_KEY = cld_stg.INTERFACE_LINE_KEY     AND INT.INTERFACE_HEADER_KEY = cld_stg.INTERFACE_HEADER_KEY     AND INT.Item_description = cld_stg.Item_description     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (5,'RECON_CLOUD_SUCCESS','SELECT     :src_cols from      PO_LINES_ALL base,     PO_LINES_INTERFACE INT ,     PO_HEADERS_INTERFACE INT_H,     :cld_stg_table cld_stg,      :src_stg_table src_stg where     1=1     and INT.po_line_id = BASE.po_line_id     AND INT.CATEGORY= cld_stg.CATEGORY     AND INT.ITEM= cld_stg.ITEM     AND INT.INTERFACE_LINE_KEY = cld_stg.INTERFACE_LINE_KEY     AND INT.INTERFACE_HEADER_KEY = cld_stg.INTERFACE_HEADER_KEY     AND INT.Item_description = cld_stg.Item_description     and INT.PROCESS_CODE = ''ACCEPTED''     AND INT_H.DOCUMENT_TYPE_CODE = ''BLANKET''     AND INT.INTERFACE_HEADER_ID = INT_H.INTERFACE_HEADER_ID     and INT.load_request_id = '':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name'' AND INT_H.INTERFACE_HEADER_KEY = cld_stg.INTERFACE_HEADER_KEY     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','','base.PO_LINE_ID base_PO_LINE_ID, base.LINE_NUM base_LINE_NUM, base.ITEM_DESCRIPTION base_ITEM_DESCRIPTION, base.LIST_PRICE base_LIST_PRICE, base.AMOUNT_RELEASED base_AMOUNT_RELEASED, base.LINE_STATUS base_LINE_STATUS, base.PO_HEADER_ID  base_PO_HEADER_ID',NULL,NULL,NULL,NULL,current_date,'riteadmin','2024-11-21','riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (5,'SQL_EXTRACTION_QUERY','SELECT                       
                             pol.po_line_id                                              interface_line_key
							,poh.po_header_id                                            interface_header_key
							--,NULL                                                        action
							,''ADD''                                                       action    --Added by Sarala
							,pol.line_num                                                line_num
							,(SELECT plt.line_type
										FROM po_line_types plt
									WHERE plt.line_type_id = pol.line_type_id)                 line_type
							,(SELECT msib.segment1
											FROM mtl_system_items_b msib
										WHERE  msib.inventory_item_id = pol.item_id
												AND ROWNUM = 1)                                         item
							,REGEXP_REPLACE(to_char(pol.item_description),CHR(9)     
																																													||''|''||CHR(10)
																																													||''|''||CHR(13), '''')    item_description
							,pol.item_revision                                           item_revision
							,(SELECT category_concat_segs
											FROM mtl_categories_v mcb
										WHERE mcb.category_id = pol.category_id)                  category
							,pol.amount                                                  committed_amount
							,( SELECT SUM(pll1.quantity - pll1.quantity_received)     
												FROM po_line_locations_all  pll1
											WHERE pol.po_line_id              = pll1.po_line_id 
													AND pol.org_id                  = pll1.org_id  
													AND NVL(pll1.closed_code,''OPEN'') = ''OPEN''
													AND NVL(pll1.cancel_flag,''#'')    != ''Y'')               quantity
							,pol.unit_meas_lookup_code                                   unit_of_measure
							,pol.unit_price                                              unit_price
							,pol.secondary_quantity                                      secondary_quantity
							,pol.secondary_unit_of_measure                               secondary_unit_of_measure
							,pol.vendor_product_num                                      vendor_product_num
							,pol.negotiated_by_preparer_flag                             negotiated_by_preparer_flag
							,(SELECT phct.hazard_class
											FROM po_hazard_classes_vl phct
										WHERE phct.hazard_class_id = pol.hazard_class_id )        hazard_class
							,NULL                                                        un_number
							,pol.note_to_vendor                                          note_to_vendor
							,NULL                                                        note_to_receiver
                            ,NULL                                                        Min_Release_Amount
                            ,NULL                                                       Expiration_Date
                            ,NULL                                                       Supplier_Part_Auxid 
                            ,NULL                                                       Supplier_Ref_Number
                            ,NULL                                                        line_attribute_category_lines
							,pol.attribute1                                              line_attribute1
							,pol.attribute2                                              line_attribute2
							,pol.attribute3                                              line_attribute3
							,pol.attribute4                                              line_attribute4
							,pol.attribute5                                              line_attribute5
