	 (6,'RECON_CLOUD_SUCCESS','SELECT     :src_cols from      PO_LINE_LOCATIONS_ALL base,     PO_LINE_LOCATIONS_INTERFACE INT,     :cld_stg_table cld_stg,      :src_stg_table src_stg where     1=1     and int.LINE_LOCATION_ID = base.LINE_LOCATION_ID     and Int.INTERFACE_LINE_LOCATION_KEY =cld_stg.INTERFACE_LINE_LOCATION_KEY     and INT.INTERFACE_LINE_KEY = cld_stg.INTERFACE_LINE_KEY     and INT.PROCESS_CODE = ''ACCEPTED''     and INT.load_request_id = '':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name''     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','',' base.line_location_id      base_line_location_id,     base.mode_of_transport     base_mode_of_transport,     base.service_level         base_service_level,     base.destination_type_code base_destination_type_code,     base.schedule_status       base_schedule_status,     base.trx_business_category base_trx_business_category,     base.prc_bu_id             base_prc_bu_id,     base.req_bu_id             base_req_bu_id,     base.product_type          base_product_type,     base.assessable_value      base_assessable_value,     base.po_header_id          base_po_header_id,     base.po_line_id            base_po_line_id,     base.quantity              base_quantity,     base.quantity_received     base_quantity_received,     base.quantity_accepted     base_quantity_accepted,     base.quantity_rejected     base_quantity_rejected,     base.quantity_billed       base_quantity_billed,     base.quantity_cancelled    base_quantity_cancelled,     base.uom_code              base_uom_code',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (6,'SQL_EXTRACTION_QUERY','SELECT
        pll.line_location_id,
        pll.po_line_id,
        pll.ship_to_location_id,
        pll.ship_to_organization_id,
        pll.line_location_id     interface_line_location_key,
        pll.po_line_id           interface_line_key,
        pll.shipment_num         price_break,
        (SELECT
            location_code
        FROM
            apps.hr_locations_all hl
        WHERE
            hl.location_id = pll.ship_to_location_id) ship_to_location,
        ((
        SELECT
            bill_hou.name
        FROM
            hr_all_organization_units bill_hou
        WHERE
            bill_hou.organization_id = pll.ship_to_organization_id
    )  ) ship_to_organization,
        pll.quantity             quantity,
        pll.price_override       price,
        pll.price_discount       discount_pct,
        pll.start_date           start_date,
        pll.end_date             end_date,
        pll.attribute_category   attribute_category,
        pll.attribute1           attribute1,
        pll.attribute2           attribute2,
        pll.attribute3           attribute3,
        pll.attribute4           attribute4,
        pll.attribute5           attribute5,
        pll.attribute6           attribute6,
        pll.attribute7           attribute7,
        pll.attribute8           attribute8,
        pll.attribute9           attribute9,
        pll.attribute10          attribute10,
        pll.attribute11          attribute11,
        pll.attribute12          attribute12,
        pll.attribute13          attribute13,
        pll.attribute14          attribute14,
        pll.attribute15          attribute15,
        NULL attribute16,
        NULL attribute17,
        NULL attribute18,
        NULL attribute19,
        NULL attribute20,
        NULL attribute_date1,
        NULL attribute_date2,
        NULL attribute_date3,
        NULL attribute_date4,
        NULL attribute_date5,
        NULL attribute_date6,
        NULL attribute_date7,
        NULL attribute_date8,
        NULL attribute_date9,
        NULL attribute_date10,
        NULL attribute_number1,
        NULL attribute_number2,
        NULL attribute_number3,
        NULL attribute_number4,
        NULL attribute_number5,
        NULL attribute_number6,
        NULL attribute_number7,
        NULL attribute_number8,
        NULL attribute_number9,
        NULL attribute_number10,
        NULL attribute_timestamp1,
        NULL attribute_timestamp2,
        NULL attribute_timestamp3,
        NULL attribute_timestamp4,
        NULL attribute_timestamp5,
        NULL attribute_timestamp6,
        NULL attribute_timestamp7,
        NULL attribute_timestamp8,
        NULL attribute_timestamp9,
        NULL attribute_timestamp10,
        ''New'' conversion_status
    FROM
        apps.po_line_locations_all pll,
		apps.po_headers_all poh,
	    apps.po_lines_all   pol
    WHERE
        nvl(
            pll.closed_code,
            ''OPEN''
        ) = ''OPEN''
        AND pll.cancel_flag = ''N''
        AND pll.po_release_id IS NULL
		AND pll.po_header_id = poh.po_header_id
		AND pll.po_line_id   = pol.po_line_id
        AND poh.po_header_id = pol.po_header_id
	    AND poh.type_lookup_code = ''BLANKET''
		AND poh.authorization_status IN ( ''APPROVED'' )
		AND poh.enabled_flag = ''Y''
		AND nvl(poh.closed_code, ''OPEN'') = ''OPEN''
		AND nvl(pol.closed_code, ''OPEN'') = ''OPEN''
        AND pll.org_id in (select hou.ORGANIZATION_ID  from hr_operating_units hou
	                               where hou.name in
												(''Biomet 3i Canada'',
													''Zimmer Dental SAS'',
													''JP OU'',
													''3i US'',
													''Biomet 3i Dental Iberica SLU''))
		','',NULL,NULL,NULL,NULL,NULL,'2025-01-02','riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (6,'RECON_CLOUD_FAIL','SELECT     :src_cols     ||      '',''     || ''"''     ||     (         SELECT               listagg (error_message,'','') WITHIN GROUP (ORDER BY interface_header_id)  error_msg         FROM             po_interface_errors         where             1=1             and interface_header_id = int.interface_header_id             and INTERFACE_LINE_ID = int.INTERFACE_LINE_ID             and INTERFACE_LINE_LOCATION_ID =int.INTERFACE_LINE_LOCATION_ID                      GROUP BY              interface_header_id || ''"''     ) Error_Message FROM     PO_LINE_LOCATIONS_INTERFACE INT,     :cld_stg_table cld_stg,      :src_stg_table src_stg WHERE     1=1     and INT.load_request_id ='':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name''     AND INT.PROCESS_CODE <>''ACCEPTED''      and Int.INTERFACE_LINE_LOCATION_KEY =cld_stg.INTERFACE_LINE_LOCATION_KEY     and INT.INTERFACE_LINE_KEY = cld_stg.INTERFACE_LINE_KEY     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
