	 (7,'SQL_EXTRACTION_QUERY','SELECT
        ph.po_header_id,
        ph.org_id,
        ph.vendor_site_id,
        ph.ship_to_location_id,
        ph.bill_to_location_id,
        ph.po_header_id   interface_bu_assignment_key,
        ph.po_header_id   interface_header_key,
        hou.name requisitioning_bu,
        NULL order_locally,
        pvs.vendor_site_code purchasing_site,
        shiphl.location_code ship_to_location,
        hou.name bill_to_bu,
        billhl.location_code bill_to_location,
        enabled_flag   enabled,
        ''New'' conversion_status
    FROM
        po_headers_all ph,
		po_vendor_sites_all pvs,
		hr_locations_all shiphl,
		hr_locations_all billhl,
		hr_operating_units hou
    WHERE
        1=1
		AND pvs.vendor_site_id = ph.vendor_site_id
		AND shiphl.location_id = ph.ship_to_location_id
		AND billhl.location_id = ph.ship_to_location_id
		AND hou.organization_id = ph.org_id
        AND ph.type_lookup_code = ''BLANKET''
		AND ph.authorization_status IN ( ''APPROVED'' )
		AND ph.enabled_flag = ''Y''
		AND nvl(ph.closed_code, ''OPEN'') = ''OPEN''
		AND hou.name in	(''Biomet 3i Canada'',
													''Zimmer Dental SAS'',
													''JP OU'',
													''3i US'',
													''Biomet 3i Dental Iberica SLU'')
		AND nvl(
					ph.end_date,
						SYSDATE + 1
					) > SYSDATE
        AND EXISTS (
						SELECT
							''x''
						FROM
							apps.po_lines_all pl
						WHERE
							pl.po_header_id = ph.po_header_id
							AND nvl(
								pl.closed_code,
								''OPEN''
							) = ''OPEN''
							AND nvl(
								pl.cancel_flag,
								''N''
							) = ''N''
							AND nvl(
								pl.expiration_date,
								SYSDATE + 1
							) > SYSDATE
					) 
        order by ph.segment1','',NULL,NULL,NULL,NULL,NULL,'2025-01-02','riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (7,'Sequence','4','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
