	 (11,'RECON_CLOUD_SUCCESS','SELECT      :src_cols from      PO_HEADERS_ALL base,     PO_HEADERS_INTERFACE INT,     :cld_stg_table cld_stg,      :src_stg_table src_stg where     1=1     and INT.po_header_id = BASE.po_header_id     AND base.TYPE_LOOKUP_CODE = ''CONTRACT''     and int.DOCUMENT_NUM = base.segment1     AND INT.DOCUMENT_NUM= cld_stg.DOCUMENT_NUM     and INT.PROCESS_CODE = ''ACCEPTED''      AND INT.DOCUMENT_TYPE_CODE = ''CONTRACT''     and INT.load_request_id ='':load_request_id''     and cld_stg.cr_batch_name = '':cr_batch_name''     and cld_stg.cr_batch_name = src_stg.cr_batch_name     and src_stg.ORIG_TRANS_ID = cld_stg.ORIG_TRANS_ID ','','base.po_header_id base_po_header_id,     base.billto_bu_id base_billto_bu_id,     base.soldto_le_id base_soldto_le_id,     base.document_status base_document_status,     base.prc_bu_id base_prc_bu_id,     base.req_bu_id base_req_bu_id,     base.segment1 base_segment1,     base.vendor_id base_vendor_id,     base.vendor_site_id base_vendor_site_id,     base.vendor_contact_id base_vendor_contact_id,     base.ship_to_location_id base_ship_to_location_id,     base.bill_to_location_id base_bill_to_location_id,     base.terms_id base_terms_id,     base.TYPE_LOOKUP_CODE base_TYPE_LOOKUP_CODE',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (12,'InterfaceDetails','22','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
