	 (19,'DocumentAccount','fin/receivables/import',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'DocumentSecurityGroup','FAFusionImportExport',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'JobName','/oracle/apps/ess/cdm/foundation/bulkImport,CDMAutoBulkImportJob',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'InterfaceDetails','4',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'RECON_CLOUD_FAIL_COUNT',' SELECT  count(1)
FROM    hz_imp_acctsites_t hip
WHERE   hip.interface_status<>''S''
and hip.load_request_id='':load_request_id'' ',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'RECON_CLOUD_SUCCESS',' SELECT    :cld_cols  from 
          hz_imp_acctsites_t hip,
          hz_cust_acct_sites_all hp,
          :cld_stg_table cld_stg
          where 
           hp.orig_system_reference=hip.cust_orig_system_reference
          AND hip.interface_status=''S''
          and cld_stg.cr_batch_name='':cr_batch_name''
          and hip.load_request_id = '':load_request_id''
          and cld_stg.SITE_ORIG_SYSTEM_REFERENCE=hip.cust_orig_system_reference
          and hip.ATTRIBUTE20 = cld_stg.ORIG_TRANS_ID ',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'RECON_CLOUD_FAIL',' SELECT :cld_cols ||'',''||
     ''"''
   ||  SELECT
            LISTAGG( distinct
			case when MESSAGE_NAME=''HZ_DUPLICATE_COMBINATION'' then  ''The combination of columns CUST_SITE_ORIG_SYSTEM and CUST_SITE_ORIG_SYS_REF must be unique in table HZ_IMP_ACCTSITES_T.''
			else MESSAGE_NAME
			end, '','') WITHIN GROUP(
            ORDER BY
                ERROR_ID
            ) AS error_msg
        FROM
            hz_imp_errors
        WHERE
                interface_table_name = ''HZ_IMP_ACCTSITES_T''
            AND error_id = hip.error_id
        GROUP BY
            error_id
||''"''
Reject_lookup_codem  

FROM
          hz_imp_acctsites_t hip,
		  :cld_stg_table cld_stg
        WHERE
            hip.interface_status<>''S''
        and cld_stg.cr_batch_name='':cr_batch_name''
        and hip.load_request_id = '':load_request_id''
        and cld_stg.SITE_ORIG_SYSTEM_REFERENCE=hip.cust_orig_system_reference
        and hip.ATTRIBUTE20 = cld_stg.ORIG_TRANS_ID ',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'Sequence','5','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (19,'SQL_EXTRACTION_QUERY','SELECT
