    hcasa.attribute11           "DFF_Segment11",
    hcasa.attribute12           "DFF_Segment12",
    hcasa.attribute13           "DFF_Segment13",
    hcasa.attribute14           "DFF_Segment14",
    hcasa.attribute15           "DFF_Segment15",
    hcasa.attribute16           "DFF_Segment16",
