    hcasa.attribute18           "DFF_Segment18",
    hcasa.attribute19           "DFF_Segment19",
    hcasa.attribute20           "DFF_Segment20",
    NULL                        "DFF_Segment21",
    NULL                        "DFF_Segment22",
    NULL                        "DFF_Segment23",
    NULL                        "DFF_Segment24",
