	 (26,'RECON_CLOUD_SUCCESS',' SELECT    :cld_cols  from 
          hz_imp_locations_t hip,
          hz_locations hp,
          :cld_stg_table cld_stg
          where 
           hip.LOCATION_ID=hp.LOCATION_ID
          and hp.orig_system_reference=hip.location_orig_system_reference
