	  and cld_stg.LOCATION_ORIG_SYSTEM_REFERENCE=hip.location_orig_system_reference ',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
