	 (31,'SQL_EXTRACTION_QUERY','select distinct  hp.PARTY_ID,
         hp.PARTY_NUMBER,
         hp.party_name,
         hp.PARTY_TYPE,
         hp.GSA_INDICATOR_FLAG,
         hp.CUSTOMER_KEY,
         hp.ORIG_SYSTEM_REFERENCE,
         hca.attribute19,
         hca.attribute20,
         hca.CUST_ACCOUNT_ID,
         hca.ACCOUNT_NUMBER,
         hca.ACCOUNT_NAME,
         hca.ORIG_SYSTEM_REFERENCE,
         hca.STATUS,
         hca.CUSTOMER_TYPE,
         hca.CUSTOMER_CLASS_CODE,
         hca.TAX_HEADER_LEVEL_FLAG,
         hcas.CUST_ACCT_SITE_ID,
         hcas.PARTY_SITE_ID,
         hcas.ORIG_SYSTEM_REFERENCE,
         hcas.STATUS,
         hcas.ORG_ID,
         hcas.BILL_TO_FLAG,
         hcas.SHIP_TO_FLAG,

        (SELECT a.NAME
           FROM ar.hz_cust_profile_classes @{0} a
          WHERE a.profile_class_id = hcp.profile_class_id
        ) profile_class_name,
        (SELECT a.NAME
           FROM ar.ar_collectors @{0} a
          WHERE a.collector_id = hcp.collector_id
        ) collector_name,
        (SELECT a.NAME
           FROM ar.ar_statement_cycles @{0} a
          WHERE statement_cycle_id = hcp.statement_cycle_id
        ) statement_cycle_name,
        (SELECT a.NAME
     FROM apps.ra_terms @{0} a
    WHERE a.term_id = hcp.standard_terms) payment_term_name,
        (SELECT a.NAME
           FROM ar.ra_grouping_rules @{0} a
          WHERE a.grouping_rule_id = hcp.grouping_rule_id) grouping_rules_name,
        (SELECT a.orig_system_reference
           FROM hz_cust_site_uses_all @{0} a
          WHERE a.site_use_id = hcp.site_use_id) profile_site_use_osr,
        hcp.credit_checking,
        hcp.tolerance,
        hcp.credit_hold,
        hcp.credit_balance_statements,
        hcp.send_statements,
        hcp.jgzz_attribute1 enable_late_charges,
        hcp.interest_charges,
        hcp.jgzz_attribute2 late_charge_calculation_trx,
        hcp.jgzz_attribute5 hold_charged_invoices_flag,
        hcp.dunning_letters,
        hcp.discount_terms,
        hcp.interest_period_days,
        hcp.payment_grace_days,
        hcp.discount_grace_days,
        hcp.auto_rec_incl_disputed_flag,
        hcp.attribute_category cust_prof_dff_category,
        hcp.attribute2 cust_prof_dff_attr2,
        hcpa.currency_code,
        hcpa.trx_credit_limit,
        hcpa.overall_credit_limit,
        hcpa.min_dunning_amount,
        hcpa.min_dunning_invoice_amount,
        hcpa.max_interest_charge,
        hcpa.min_statement_amount,
        hcpa.auto_rec_min_receipt_amount,
        hcpa.interest_rate,
        hcpa.min_fc_balance_amount,
        hcpa.min_fc_invoice_amount
    from ar.hz_parties             @{0} hp,
         ar.hz_cust_accounts       @{0} hca,
         ar.hz_cust_acct_sites_All @{0} hcas,
         ar.hz_customer_profiles   @{0} hcp,
         ar.hz_cust_profile_amts   @{0} hcpa

   where hp.party_id = hca.party_id
    AND hca.cust_account_id = hcas.cust_account_id
    AND hca.cust_account_id          = hcp.cust_account_id
    and hcp.cust_account_profile_id = hcpa.cust_account_profile_id(+)','',NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);

