	 (38,'InterfaceDetails','26',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (38,'DocumentAccount','prc/supplier/import',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (38,'RECON_CLOUD_FAIL_COUNT','SELECT     COUNT(1) FROM     POZ_SUP_CONTACTS_INT WHERE         import_status <> ''PROCESSED''     AND load_request_id = '':load_request_id''','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (38,'RECON_CLOUD_SUCCESS','SELECT     :src_cols FROM     POZ_SUP_CONTACTS_INT int,     POZ_SUPPLIER_CONTACTS base,     :cld_stg_table cld_stg ,     :src_stg_table src_stg WHERE     1=1     AND int.import_status = ''PROCESSED''     AND cld_stg.cr_batch_name = '':cr_batch_name''     AND int.load_request_id = :load_request_id     AND src_stg.orig_trans_id = cld_stg.orig_trans_id     AND cld_stg.vendor_name = int.vendor_name     AND Int.PER_PARTY_ID = base.PER_PARTY_ID     AND src_stg.cr_batch_name = cld_stg.cr_batch_name','','base.vendor_contact_id base_vendor_contact_id,        base.relationship_id base_relationship_id,        base.org_party_site_id base_org_party_site_id,        base.party_site_id base_party_site_id,       base.org_contact_id base_org_contact_id',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (38,'RECON_CLOUD_FAIL','SELECT     :src_cols     || '',''     || ''"''     || (         SELECT             LISTAGG(reject_lookup_code, '','') WITHIN GROUP(             ORDER BY                 parent_id             ) error_msg         FROM             poz_supplier_int_rejections         WHERE                 parent_table = ''POZ_SUP_CONTACTS_INT''             AND request_id = int.request_id             AND int.vendor_interface_id = parent_id         GROUP BY             request_id || ''"''     ) reject_lookup_code FROM     poz_sup_contacts_int int,     :cld_stg_table cld_stg,     :src_stg_table src_stg WHERE     1 = 1     AND int.import_status = ''REJECTED''     AND cld_stg.cr_batch_name = '':cr_batch_name''     AND int.load_request_id = '':load_request_id''     AND src_stg.orig_trans_id = cld_stg.orig_trans_id     AND cld_stg.vendor_name = int.vendor_name     AND src_stg.cr_batch_name = cld_stg.cr_batch_name','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);

