     (46,'DocumentAccount','prc/purchaseOrder/import','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
