	 (46,'InterfaceDetails','21','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (46,'JobName','/oracle/apps/ess/prc/po/pdoi/,ImportSPOJob','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (46,'SQL_EXTRACTION_QUERY','
SELECT poh.po_header_id                                                         interface_header_key
							,''ORIGINAL''                                         action               --Added by Sarala
							,NULL                                                                     batch_id
							,poh.interface_source_code                                                interface_source_code
							--,decode(poh.authorization_status,''REQUIRES REAPPROVAL'',''NONE'',''BYPASS'')   approval_action           --None,ByPass,Submit
							,NULL                                                                    approval_action
							,poh.segment1                                                             document_num
							,''STANDARD''                                                                     document_type_code
							 --,poh.type_lookup_code                                                     document_type_code --Added by Sarala
							,NULL                                                                     style_display_name
							,(SELECT bill_hou.name
											FROM hr_operating_units  bill_hou
										WHERE bill_hou.organization_id = poh.org_id)                           prc_bu_name
							--,NULL                                                                     req_bu_name
							,(SELECT bill_hou.name
