     (56,'SQL_EXTRACTION_QUERY','SELECT
    gdr.from_currency                           from_currency,
    gdr.to_currency                             to_currency,
    to_char(gdr.creation_date, ''YYYY/MM/DD'')    from_conversion_date,
    to_char(gdr.last_update_date, ''YYYY/MM/DD'') to_conversion_date,
    ''Corporate''                                 user_conversion_type,
    glr.conversion_rate                         conversion_rate,
    NULL                                        inverse_conversion_rate,
    NULL                                        attribute_category,
    glr.attribute1,
    glr.attribute2,
    glr.attribute3,
    glr.attribute4,
    glr.attribute5,
    glr.attribute6,
    glr.attribute7,
    glr.attribute8,
    glr.attribute9,
    glr.attribute10,
    glr.attribute11,
    glr.attribute12,
    glr.attribute13,
    glr.attribute14,
    glr.attribute15,
    NULL                                        attribute_date1,
    NULL                                        attribute_date2,
    NULL                                        attribute_date3,
    NULL                                        attribute_date4,
    NULL                                        attribute_number1,
    NULL                                        attribute_number2,
    NULL                                        attribute_number3,
    NULL                                        attribute_number4,
    NULL                                        attribute_number5
FROM
    gl_cross_rate_rule_dtls gdr,
    gl_daily_rates          glr
WHERE
    gdr.conversion_type = glr.conversion_type (+)','',NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(56,'Sequence','6',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);


