	NULL NEW_PRIMARY_UOM_NAME,
    NULL NEW_SECONDARY_UOM_NAME,
    NULL PARTS_SOURCING_NAME	,
    NULL ORDER_MODIFIER_START_QTY_FLAG
FROM
    mtl_system_items_b  @{0} esib,
  --MTL_SYSTEM_ITEMS_B ESIV,
    mtl_parameters   @{0}  base_iop--,
--MTL_units_of_measure_TL uom --, 
--egp_item_classes_b icls,
--ra_terms rt

WHERE
        1 = 1
    AND esib.organization_id = base_iop.organization_id
--AND ESIB.INVENTORY_ITEM_ID = ESIV.INVENTORY_ITEM_ID
--AND ESIB.ORGANIZATION_ID = ESIV.ORGANIZATION_ID
--AND ESIV.LANGUAGE = USERENV(''LANG'')
---and esib.primary_uom_code = uom.uom_code
--and icls.item_class_id = esib.item_catalog_group_id
---and esib.payment_terms_id = rt.term_id(+)
--and base_iop.organization_code = ''204''--MASTER ORGANIZATION CODE
 ---and esib.enabled_flag = ''Y''
    AND esib.inventory_item_id IN (
        SELECT DISTINCT
            inventory_item_id
        FROM
            mtl_system_items_b  esb, mtl_parameters  iop
WHERE
        esb.organization_id = iop.organization_id
    AND esb.enabled_flag = ''Y''
            --AND iop.organization_id = 204 --MASTER ORGANIZATION ID
            --and iop.organization_code in  (''CN_CONSIGN'', ''CN_MAIN'', ''IN_CONSIGN'' ,''IN_MAIN'')
    )
    AND esib.segment1 IN (''CM74123'', ''CM74237'', ''CM76962'', ''CM89108'')','',NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);


