	 (67,'RECON_CLOUD_FAIL_COUNT','SELECT 	     count(1)  FROM 	     EGP_ITEM_CATEGORIES_INTERFACE  WHERE 	     1=1     AND PROCESS_STATUS <> ''7''     AND load_request_id ='':load_request_id''','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (67,'RECON_CLOUD_FAIL','SELECT     :src_cols     || '',''     || ''"''     || (         SELECT             LISTAGG(message_text, '','') WITHIN GROUP(             ORDER BY                 transaction_id             ) error_msg         FROM             egp_import_errors         WHERE                 error_table_name = ''EGP_ITEM_CATEGORIES_INTERFACE''             AND transaction_id = int.transaction_id         GROUP BY             transaction_id || ''"''     ) reject_lookup_codefrom FROM     egp_item_categories_interface int,	      :cld_stg_table cld_stg,		     : src_stg_table src_stg WHERE     1 = 1     AND int.process_status <> ''7''     AND cld_stg.cr_batch_name = '':cr_batch_name''     AND int.load_request_id = '':load_request_id''     AND int.source_system_reference = cld_stg.orig_trans_id     AND src_stg.orig_trans_id = cld_stg.orig_trans_idand     AND src_stg.cr_batch_name = cld_stg.cr_batch_name','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
