INSERT INTO cr_object_information (object_id,info_type,info_value,info_description,additional_information1,additional_information2,additional_information3,additional_information4,additional_information5,creation_date,created_by,last_update_date,last_update_by,attribute1,attribute2,attribute3,attribute4,attribute5,attribute6,attribute7,attribute8,attribute9,attribute10,attribute11,attribute12,attribute13,attribute14,attribute15) VALUES
	 (121,'Sequence','1',NULL,NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (121,'DocumentSecurityGroup','FAFusionImportExport','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (121,'Enable Object','Y','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	 (121,'SQL_EXTRACTION_QUERY','SELECT DISTINCT
        (SELECT territory_short_name 
		 FROM  fnd_territories_vl 
		 WHERE territory_code=abb.country) country,
        abb.bank_name,
        abb.bank_number bank_code, 
        abb.bank_name_alt      alternate_bank_name,
        abb.bank_branch_name   branch_name,
        abb.bank_num           branch_number,
        eft_swift_code bic_code,
        bank_branch_name_alt   alternate_branch_name,
        bank_branch_type       bank_branch_type,
        NULL eft_number,
        NULL edi_id_number,
        NULL edi_location,
        NULL account_name,
        NULL account_number,
        NULL currency,
        NULL legal_entity,
        NULL account_type,
        NULL iban,
        NULL alternate_account_name,
        NULL payable_use,
        NULL receivable_use,
        NULL cash_account,
        NULL cash_clearing_account
    FROM
        apps.ap_bank_branches       abb,
        apps.ap_bank_accounts_all   aba
    WHERE
        aba.bank_branch_id = abb.bank_branch_id
        AND EXISTS (
            SELECT
                ''x''
            FROM
                apps.ap_bank_account_uses_all bau
            WHERE
                bau.vendor_id IS NOT NULL
                AND nvl(
                    bau.end_date,
                    SYSDATE + 1
                ) > SYSDATE
                AND EXISTS (
                    SELECT
                        ''x''
             FROM       po_vendors pv,
					po_vendor_sites_all pvsa,
					hr_operating_units hou
			WHERE nvl(pv.end_date_active,SYSDATE + 1) > SYSDATE
			AND nvl(pvsa.inactive_date,SYSDATE + 1) > SYSDATE
			AND pv.vendor_id=pvsa.vendor_id
			AND pvsa.org_id=hou.organization_id
			AND pv.enabled_flag = ''Y''
			AND hou.name in (''Biomet 3i Canada'',
							 ''Zimmer Dental SAS'',
							 ''JP OU'',
							 ''3i US'',
							 ''Biomet 3i Dental Iberica SLU'')
                )
                AND bau.external_bank_account_id = aba.bank_account_id
        )
		
		UNION 
	SELECT DISTINCT
        (SELECT territory_short_name 
		 FROM  fnd_territories_vl 
		 WHERE territory_code=abb.country)   country,
        abb.bank_name,
        abb.bank_number bank_code, 
        abb.bank_name_alt      alternate_bank_name,
        abb.bank_branch_name   branch_name,
        abb.bank_num           branch_number,
        eft_swift_code bic_code,
        bank_branch_name_alt   alternate_branch_name,
        bank_branch_type       bank_branch_type,
        NULL eft_number,
        NULL edi_id_number,
        NULL edi_location,
        NULL account_name,
        NULL account_number,
        NULL currency,
        NULL legal_entity,
        NULL account_type,
        NULL iban,
        NULL alternate_account_name,
        NULL payable_use,
        NULL receivable_use,
        NULL cash_account,
        NULL cash_clearing_account
    FROM
        apps.ap_bank_branches       abb,
        apps.ap_bank_accounts_all   aba
    WHERE
        aba.bank_branch_id = abb.bank_branch_id
        AND EXISTS (
            SELECT
                ''x''
            FROM
                apps.ap_bank_account_uses_all bau
            WHERE
                bau.customer_id IS NOT NULL
                AND nvl(
                    bau.end_date,
                    SYSDATE + 1
                ) > SYSDATE
                AND EXISTS (
                    SELECT
                        ''x''
				FROM
					hz_parties       hz,
					hz_cust_accounts hca
				WHERE
						1 = 1
					AND hz.party_id = hca.party_id
					AND hca.STATUS=''A''
					AND hz.STATUS=''A''
					AND hz.party_id IN (select 
											   hps.party_id 
										from 
											 hz_cust_acct_sites_all hcasa,
											 hz_party_sites hps,
											 hr_operating_units hou
										where 
											 hcasa.party_site_id=hps.party_site_id
										AND  hcasa.org_id=hou.ORGANIZATION_ID
										AND  hps.status=''A''
										AND  hcasa.status=''A''
										AND  hou.name in (''Biomet 3i Canada'',
															''Zimmer Dental SAS'',
															''JP OU'',
															''3i US'',
															''Biomet 3i Dental Iberica SLU'')
										)  
                )
                AND bau.external_bank_account_id = aba.bank_account_id
        )  ','',NULL,NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(121,'DocumentAccount','hcm$/dataloader$/import$','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL); 

