INSERT INTO cr_object_information (object_id,info_type,info_value,info_description,additional_information1,additional_information2,additional_information3,additional_information4,additional_information5,creation_date,created_by,last_update_date,last_update_by,attribute1,attribute2,attribute3,attribute4,attribute5,attribute6,attribute7,attribute8,attribute9,attribute10,attribute11,attribute12,attribute13,attribute14,attribute15) VALUES
	(190,'RECON_CLOUD_FAIL_COUNT','SELECT  count(1)  FROM    CST_INTERFACE_STD_COST_HEADERS  WHERE    PROCESSING_STATUS <> ''S''  AND load_request_id = '':load_request_id''','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'InterfaceDetails','34','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'JobName','/oracle/apps/ess/scm/costing/standardCosts/stdCostInterface,cstStdCostInterfaceJob','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'Sequence','1','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'DocumentAccount','scm/standardCost/import','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'DocumentSecurityGroup','FAFusionImportExport','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'RECON_CLOUD_SUCCESS','SELECT      :src_cols FROM     CST_INTERFACE_STD_COST_HEADERS int,     CST_STD_COSTS base,     EGP_SYSTEM_ITEMS_B Item_base,     :cld_stg_table cld_stg,      :src_stg_table src_stg WHERE     1 = 1     AND int.PROCESSING_STATUS = ''S''     AND cld_stg.cr_batch_name = '':cr_batch_name''     AND int.load_request_id ='':load_request_id''     AND src_stg.orig_trans_id = cld_stg.orig_trans_id     AND cld_stg.EXTERNAL_SYSTEM_REF_ID = int.EXTERNAL_SYSTEM_REF_ID     AND cld_stg.ITEM_NUMBER = int.ITEM_NUMBER     AND int.ITEM_NUMBER = Item_base.ITEM_NUMBER     AND Item_base.inventory_item_id = base.inventory_item_id     AND Item_base.organization_id = base.INVENTORY_ORG_ID','','base.std_cost_id       base_std_cost_id,     base.cost_org_id       base_cost_org_id,     base.inventory_item_id base_inventory_item_id,     base.inventory_org_id  base_inventory_org_id,     base.total_cost        base_total_cost,     base.currency_code     base_currency_code',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL),
	(190,'RECON_CLOUD_FAIL','SELECT     :src_cols     ||     '',''     || ''"''     || (         SELECT             LISTAGG(message_text, '','') WITHIN GROUP(             ORDER BY                 EXTERNAL_SYSTEM_REF_ID             ) error_msg         FROM             CST_INTERFACE_MESSAGES         WHERE                 EXTERNAL_SYSTEM_REFERENCE = int.EXTERNAL_SYSTEM_REFERENCE             AND EXTERNAL_SYSTEM_REF_ID = int.EXTERNAL_SYSTEM_REF_ID         GROUP BY             EXTERNAL_SYSTEM_REF_ID || ''"''     ) reject_lookup_code FROM     CST_INTERFACE_STD_COST_HEADERS int,     :cld_stg_table cld_stg,     :src_stg_table src_stg WHERE     1=1     AND int.PROCESSING_STATUS <> ''S''     AND cld_stg.cr_batch_name ='':cr_batch_name''     AND int.load_request_id = '':load_request_id''     AND src_stg.orig_trans_id = cld_stg.orig_trans_id     AND cld_stg.EXTERNAL_SYSTEM_REF_ID = int.EXTERNAL_SYSTEM_REF_ID     AND cld_stg.ITEM_NUMBER = int.ITEM_NUMBER     AND src_stg.cr_batch_name = cld_stg.cr_batch_name','','',NULL,NULL,NULL,NULL,current_date,'riteadmin',current_date,'riteadmin',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
	

